import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import TopicSidebar from '../components/TopicSidebar';

function ThreadDetail() {
  const { id } = useParams();
  const [thread, setThread] = useState(null);
  const [comments, setComments] = useState([]);
  const [comment, setComment] = useState('');

  useEffect(() => {
    axios.get(`http://localhost:5000/api/discussion/${id}`)
      .then(response => {
        setThread(response.data.discussion);
        setComments(response.data.comments);
      })
      .catch(error => console.error('Error fetching thread:', error));
  }, [id]);

  const handlePostComment = () => {
    axios.post('http://localhost:5000/api/comment', { discussion_id: id, user: 'You', message: comment })
      .then(() => setComments([...comments, { user: 'You', message: comment, likes: 0 }]))
      .catch(error => console.error('Error posting comment:', error));
  };

  return thread ? (
    <div>
      <h1>{thread.title}</h1>
      <p>{thread.content}</p>
      <h3>Replies</h3>
      {comments.map((reply, index) => (
        <p key={index}>{reply.message}</p>
      ))}
      <textarea value={comment} onChange={e => setComment(e.target.value)} />
      <button onClick={handlePostComment}>Post</button>
    </div>
  ) : (
    <div>Loading...</div>
  );
}

export default ThreadDetail;
